using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a resource from the external API by its identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to fetch")] string resourceId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {ResourceId}", resourceId);
        var response = await httpClient.GetAsync($"/api/resources/{resourceId}", cancellationToken);
        response.EnsureSuccessStatusCode();
        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Successfully fetched resource {ResourceId}", resourceId);
        return content;
    }

    [McpServerTool, Description("Search the external API for resources matching a query string.")]
    public async Task<string> SearchResources(
        [Description("The search query to find matching resources")] string query,
        [Description("Maximum number of results to return (1-100)")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources with query '{Query}', max {Max}", query, maxResults);
        var url = $"/api/resources?q={Uri.EscapeDataString(query)}&limit={Math.Clamp(maxResults, 1, 100)}";
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a single concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize the provided content with a specific focus or angle.")]
    public static ChatMessage SummarizeWithFocus(
        [Description("The content to summarize")] string content,
        [Description("The specific aspect or angle to focus the summary on")] string focus) =>
        new(ChatRole.User,
            $"Summarize the following content into a single concise paragraph, focusing on {focus}:\n\n{content}");
}

